import{_ as r,C as i,o as e,c as s,a2 as a,b as n,w as l,a as h,E as d,a3 as u}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"GAAP vs 真实盈利","description":"为什么会计盈利不等于真实盈利？巴菲特的所有者收益概念","frontmatter":{"title":"GAAP vs 真实盈利","description":"为什么会计盈利不等于真实盈利？巴菲特的所有者收益概念"},"headers":[],"relativePath":"02_concepts/accounting-earnings.md","filePath":"02_concepts/accounting-earnings.md"}'),c={name:"02_concepts/accounting-earnings.md"};function A(q,t,p,b,f,g){const o=i("Mermaid");return e(),s("div",null,[t[1]||(t[1]=a('<h1 id="gaap-vs-真实盈利-所有者收益" tabindex="-1">GAAP vs 真实盈利（所有者收益） <a class="header-anchor" href="#gaap-vs-真实盈利-所有者收益" aria-label="Permalink to &quot;GAAP vs 真实盈利（所有者收益）&quot;">​</a></h1><blockquote><p>&quot;真正重要的是每股所有者收益——而不是GAAP收益。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>巴菲特每年在股东信中都会对比GAAP会计盈利与真实的经济盈利。他用&quot;所有者收益&quot;(owner earnings)这个概念来衡量企业为股东创造的真实价值。这个主题贯穿了从合伙企业时代(1957-1970)到伯克希尔时代(1971-至今)的全部70年。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1983年/核心总结</td><td style="text-align:left;">1983年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1986年/核心总结</td><td style="text-align:left;">1986年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1993年/核心总结</td><td style="text-align:left;">1993年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2000年/核心总结</td><td style="text-align:left;">2000年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2019年/核心总结</td><td style="text-align:left;">2019年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2022年/核心总结</td><td style="text-align:left;">2022年]]**</td></tr></tbody></table><hr><h2 id="一、什么是gaap盈利-vs-所有者收益" tabindex="-1">一、什么是GAAP盈利 vs 所有者收益 <a class="header-anchor" href="#一、什么是gaap盈利-vs-所有者收益" aria-label="Permalink to &quot;一、什么是GAAP盈利 vs 所有者收益&quot;">​</a></h2><h3 id="gaap-会计规则的游戏" tabindex="-1">GAAP：会计规则的游戏 <a class="header-anchor" href="#gaap-会计规则的游戏" aria-label="Permalink to &quot;GAAP：会计规则的游戏&quot;">​</a></h3><p>巴菲特在1988年信中直言不讳地批评GAAP的局限：</p><blockquote><p>&quot;尽管公认会计准则GAAP有缺点，我也不想设计更好的规则，但是现有规则的局限，不代表管理者不用告诉你，CEO也有义务告诉股东债权人关键信息，任何子公司经理，给母公司CEO交报表，要是只给你GAAP barebones数字，漏了关键信息，母公司CEO肯定生气，所以为什么CEO，他老板就是股东，为什么不告诉股东对他们关键有用的信息呢？&quot;</p></blockquote><blockquote><p>&quot;你需要报告的数据，不管GAAP非GAAP extra-GAAP，都要帮你回答三个关键问题：(1) 这家公司大概值多少钱？(2) 未来能不能履行义务？(3) 经理现在干得怎么样，给定拿到的这手牌。大多数情况下，GAAP没办法回答一个或多个问题，我们尝试补充信息，帮你回答。&quot;</p></blockquote><p>1986年，巴菲特更直接地说：</p><blockquote><p>&quot;此外，<a href="/search.html?q=Scott_Fetzer">Scott_Fetzer</a>收购按照GAAP要求，购买价格还要做其他 major 调整，当然GAAP数字就是合并报表用的，但我们认为，对投资者和经理不一定最有用，所以各个运营单位我们报的盈利，不包含购买价格调整，相当于，就是我们没买这家企业，它本来会报告的盈利。&quot;</p></blockquote><h3 id="所有者收益-真正属于股东的钱" tabindex="-1">所有者收益：真正属于股东的钱 <a class="header-anchor" href="#所有者收益-真正属于股东的钱" aria-label="Permalink to &quot;所有者收益：真正属于股东的钱&quot;">​</a></h3><p>1983年，巴菲特首次系统阐述了他的所有者收益公式：</p><blockquote><p>&quot;GAAP会计要求在合并报表时确认我们被投资公司留存的所有经营收益，即使这些收益从未分配给我们。&quot;</p></blockquote><blockquote><p>&quot;实际上，代表了我们真正可以自由支配的留存收益——我们可以在留存它们或分配给股东之间做出选择。&quot;</p></blockquote><hr><h2 id="二、留存收益-被忽视的财富引擎" tabindex="-1">二、留存收益：被忽视的财富引擎 <a class="header-anchor" href="#二、留存收益-被忽视的财富引擎" aria-label="Permalink to &quot;二、留存收益：被忽视的财富引擎&quot;">​</a></h2><h3 id="史密斯的教训" tabindex="-1">史密斯的教训 <a class="header-anchor" href="#史密斯的教训" aria-label="Permalink to &quot;史密斯的教训&quot;">​</a></h3><p>2019年信开篇，巴菲特用1924年经济学家埃德加·劳伦斯·史密斯的故事开篇：</p><blockquote><p>&quot;1924年，一位名不见经传的经济学家兼财务顾问埃德加·劳伦斯·史密斯撰写了《普通股作为长期投资》一书，这本薄薄的书改变了投资世界。起初，他打算论证股票在通胀时期表现会优于债券，而债券在通缩时期会提供更高的回报。这似乎足够合理。但史密斯却大吃一惊。&quot;</p></blockquote><blockquote><p>&quot;他的书以一段忏悔开始：这些研究是一份失败的记录——事实是，事实未能支撑先入为主的理论。幸运的是，对投资者来说，这次失败促使史密斯更深入地思考应该如何评估股票。&quot;</p></blockquote><blockquote><p>&quot;尽管投资者醒悟得很慢，但留存和再投资收益的数学原理现在已被充分理解。今天，学童们都能学到凯恩斯所说的新颖观点：将储蓄与复利结合，会创造奇迹。&quot;</p></blockquote><h3 id="伯克希尔的留存收益实践" tabindex="-1">伯克希尔的留存收益实践 <a class="header-anchor" href="#伯克希尔的留存收益实践" aria-label="Permalink to &quot;伯克希尔的留存收益实践&quot;">​</a></h3><blockquote><p>&quot;在<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>，查理和我长期以来一直专注于有利地利用留存收益。有时这项工作很容易——在其他时候，则相当困难，特别是当我们开始处理巨额且不断增长的资金时。&quot;</p></blockquote><blockquote><p>&quot;在对留存资金的配置中，我们首先寻求投资于我们已经拥有的众多多元化业务。在过去十年中，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>的折旧费用累计达650亿美元，而公司在财产、厂房和设备方面的内部投资总计达1210亿美元。&quot;</p></blockquote><hr><h2 id="三、为什么gaap具有误导性" tabindex="-1">三、为什么GAAP具有误导性 <a class="header-anchor" href="#三、为什么gaap具有误导性" aria-label="Permalink to &quot;三、为什么GAAP具有误导性&quot;">​</a></h2><p>1993年，巴菲特详细解释了他透视收益的逻辑：</p><blockquote><p>&quot;按照我们的计算方法，透视收益包括：(1)上一部分报告的经营收益，加上(2)主要被投资公司的留存经营收益（根据GAAP会计，这些不反映在我们的利润中），减去(3)如果这些被投资公司的留存收益分配给我们，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>将要支付的税款估算。&quot;</p></blockquote><blockquote><p>&quot;我们这里所说的经营收益不包括资本利得、特殊会计项目和重大重组费用。&quot;</p></blockquote><p>他随后举例说明GAAP如何低估了真实收益：</p><blockquote><p>&quot;1986年我们以每股172.50美元购买了300万股<a href="/03_companies/大都会.html">大都会</a>/<a href="/search.html?q=首都城市ABC">首都城市ABC</a>股票，去年年底以每股630美元出售了其中的三分之一。在支付35%的资本利得税后，我们从出售中实现了2.97亿美元的利润。相比之下，在我们持有这些股票的八年中，归属于它们的Cap Cities留存收益——按照我们的透视方法以较低的14%税率假设征税——仅为1.52亿美元。换言之，我们支付的税单远大于我们向您展示的透视收益所假设的税额。&quot;</p></blockquote><hr><h2 id="四、2022年的gaap季度波动" tabindex="-1">四、2022年的GAAP季度波动 <a class="header-anchor" href="#四、2022年的gaap季度波动" aria-label="Permalink to &quot;四、2022年的GAAP季度波动&quot;">​</a></h2><p>2022年，巴菲特用一份季度对比表生动展示了GAAP的荒谬性：</p><table tabindex="0"><thead><tr><th style="text-align:left;">2022年季度</th><th style="text-align:left;">GAAP收益（十亿美元）</th><th style="text-align:left;">运营收益（十亿美元）</th></tr></thead><tbody><tr><td style="text-align:left;">第一季度</td><td style="text-align:left;">7.0</td><td style="text-align:left;">5.5</td></tr><tr><td style="text-align:left;">第二季度</td><td style="text-align:left;">9.3</td><td style="text-align:left;">(43.8)</td></tr><tr><td style="text-align:left;">第三季度</td><td style="text-align:left;">7.8</td><td style="text-align:left;">(2.7)</td></tr><tr><td style="text-align:left;">第四季度</td><td style="text-align:left;">6.7</td><td style="text-align:left;">18.2</td></tr></tbody></table><blockquote><p>&quot;无论按季度还是年度来看，GAAP收益都100%具有误导性。诚然，资本收益在过去几十年对<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>非常重要，我们预计在未来几十年也将很重要。但按季度来衡量GAAP收益——有时甚至按年度——就像根据天气来评价你的一天。&quot; —— 2022年</p></blockquote><hr><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2>',42)),(e(),n(u,null,{default:l(()=>[d(o,{id:"mermaid-261",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5BGAAP%20vs%20%E7%9C%9F%E5%AE%9E%E7%9B%88%E5%88%A9%5D%20--%3E%20B%5B%E5%86%85%E5%9C%A8%E4%BB%B7%E5%80%BC%5D%0A%20%20%20%20A%20--%3E%20C%5B%E5%A4%8D%E5%88%A9%5D%0A%20%20%20%20A%20--%3E%20D%5B%E7%95%99%E5%AD%98%E6%94%B6%E7%9B%8A%5D%0A%20%20%20%20A%20--%3E%20E%5B%E8%B5%84%E6%9C%AC%E9%85%8D%E7%BD%AE%5D%0A%20%20%20%20A%20--%3E%20F%5B%E8%82%A1%E7%A5%A8%E5%9B%9E%E8%B4%AD%5D%0A"})]),fallback:l(()=>[...t[0]||(t[0]=[h(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="/search.html?q=内在价值">内在价值</a> - 真实盈利是内在价值的基础</li><li><a href="/search.html?q=复利">复利</a> - 留存收益如何通过复利创造财富</li><li><a href="/search.html?q=资本配置">资本配置</a> - 管理层如何配置留存收益</li><li><a href="/search.html?q=股票回购">股票回购</a> - 回购与留存收益的关系</li></ul><hr><p><em>本页面整理自<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>致股东信原文（1957-2024年），<a href="/search.html?q=慢慢变富的卡尔">慢慢变富的卡尔</a>编辑整理</em></p>',5))])}const x=r(c,[["render",A]]);export{_ as __pageData,x as default};
